        attrs.set(HtmlAttr::Aria(AriaAttr::Expanded), if is_active { "true" } else { "false" });
        attrs.set(HtmlAttr::Aria(AriaAttr::Controls), content_id);
        attrs.set(HtmlAttr::TabIndex, if is_focused { "0" } else { "-1" });
