        attrs
            .set(HtmlAttr::Id, self.ctx.ids.item("item", key))
            .set(HtmlAttr::Role, role)
            .set(HtmlAttr::TabIndex, if highlighted { "0" } else { "-1" });

        if highlighted {
            attrs.set_bool(HtmlAttr::Data("ars-highlighted"), true);
