+/// Menu bar anatomy parts.
+#[derive(ComponentPart)]
+#[scope = "menu-bar"]
+pub enum Part {
+    /// Root menubar container.
+    Root,
+
+    /// Top-level menu wrapper.
+    Menu {
+        /// Menu key.
+        key: Key,
+    },
+
+    /// Top-level menu trigger.
+    MenuTrigger {
+        /// Menu key.
+        key: Key,
+    },
+
